 namespace WPAICG\Core\Stream\Contexts\AIForms; use WP_Error; if (!defined('ABSPATH')) { exit; } require_once __DIR__ . '/process/methods.php'; function process_ai_forms_logic( SSEAIFormsStreamContextHandler $handlerInstance, array $cached_data, array $get_params ): array|WP_Error { $validated_params = Process\validate_request_logic($handlerInstance, $cached_data, $get_params); if (is_wp_error($validated_params)) { return $validated_params; } $form_id = $validated_params['form_id']; $submitted_fields = $validated_params['user_input_values']; $form_config = $validated_params['form_config']; $final_prompt = Process\build_prompt_logic($form_config, $submitted_fields); if (is_wp_error($final_prompt)) { return $final_prompt; } $moderation_text = Process\build_moderation_text_logic($form_config, $submitted_fields); if (class_exists(\WPAICG\Core\AIPKit_Content_Moderator::class)) { $moderation_context = [ 'client_ip' => $validated_params['client_ip'], 'bot_settings' => [ 'provider' => $form_config['ai_provider'] ?? 'OpenAI' ], 'module' => 'ai_forms', ]; $moderation_check = \WPAICG\Core\AIPKit_Content_Moderator::check_content($moderation_text, $moderation_context); if (is_wp_error($moderation_check)) { return $moderation_check; } } $ai_caller = $handlerInstance->get_ai_caller(); $vector_store_manager = $handlerInstance->get_vector_store_manager(); $system_instruction = $form_config['system_instruction'] ?? ''; $vector_search_scores = []; if ($ai_caller && $vector_store_manager && ($form_config['enable_vector_store'] ?? '0') === '1') { $vector_search_context = \WPAICG\Core\Stream\Vector\build_vector_search_context_logic( $ai_caller, $vector_store_manager, $final_prompt, $form_config, $form_config['ai_provider'], null, null, null, null, null, null, null, $vector_search_scores ); if (!empty($vector_search_context)) { $system_instruction = !empty($system_instruction) ? $vector_search_context . "\n\n---\n\n" . $system_instruction : $vector_search_context; } } return Process\prepare_stream_data_logic($handlerInstance, $validated_params, $form_config, $final_prompt, $system_instruction, $vector_search_scores); } 